from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    if not triples:
        return ""

    from collections import defaultdict

    # Helper to join multiple objects with commas and 'and'
    def join_objs(objs: list[str]) -> str:
        if not objs:
            return ""
        if len(objs) == 1:
            return objs[0]
        return ", ".join(objs[:-1]) + " and " + objs[-1]

    # Mapping from predicate to a clause builder that returns a full clause including the subject
    def build_clause(subject: str, pred: str, objs: list[str]) -> str:
        # Helper to add possessive suffix
        def poss(s: str) -> str:
            return s + "'" if s.endswith('s') else s + "'s"

        if pred == "birthDate":
            return f"{subject} was born on {objs[0]}"
        if pred in ("birthYear", "birthPlace"):
            return f"{subject} was born in {objs[0]}"
        if pred == "origin":
            return f"{subject} originates from {objs[0]}"
        if pred == "genre":
            return f"{poss(subject)} genre is {join_objs(objs)}"
        if pred == "instrument":
            return f"{subject} plays {join_objs(objs)}"
        if pred == "occupation":
            return f"{subject} works as {join_objs(objs)}"
        if pred == "nationality":
            return f"{subject} is {join_objs(objs)}"
        if pred == "associatedBand/associatedMusicalArtist":
            return f"{subject} is associated with {join_objs(objs)}"
        if pred == "recordLabel":
            return f"{subject} is signed to {join_objs(objs)}"
        if pred == "activeYearsStartYear":
            return f"{subject} started their career in {join_objs(objs)}"
        if pred == "activeYearsEndYear":
            return f"{subject} ended their career in {join_objs(objs)}"
        if pred == "deathDate":
            return f"{subject} died on {join_objs(objs)}"
        if pred == "deathPlace":
            return f"{subject} died in {join_objs(objs)}"
        if pred == "alternativeName":
            return f"{subject} is also known as {join_objs(objs)}"
        if pred == "stylisticOrigin":
            return f"{subject} has its stylistic origins in {join_objs(objs)}"
        if pred == "musicFusionGenre":
            return f"{subject} has a fusion genre {join_objs(objs)}"
        if pred == "derivative":
            return f"{subject} is a derivative of {join_objs(objs)}"
        # fallback generic clause
        return f"{subject} {pred.replace('_', ' ')} {join_objs(objs)}"

    # Group objects by (subject, predicate)
    groups = defaultdict(list)  # type: dict[tuple[str, str], list[str]]
    for t in triples:
        groups[(t.subject, t.predicate)].append(t.object)

    main_subject = triples[0].subject
    sentences = []

    # Build sentence for the main subject aggregating its predicates
    main_clauses = []
    for (sub, pred), objs in groups.items():
        if sub != main_subject:
            continue
        phrase = build_clause(sub, pred, objs)
        if phrase:
            main_clauses.append(phrase)

    if main_clauses:
        main_sentence = f"{main_subject} " + ", ".join(main_clauses) + "."
        sentences.append(main_sentence[0].upper() + main_sentence[1:])

    # Build separate sentences for other subjects
    for (sub, pred), objs in groups.items():
        if sub == main_subject:
            continue
        phrase = build_clause(sub, pred, objs)
        if phrase:
            other_sentence = f"{phrase}."
            sentences.append(other_sentence[0].upper() + other_sentence[1:])

    return " ".join(sentences)

# EVOLVE-BLOCK-END

